output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?country ?hdi_value ?population_growth_value ?male_value ?female_value WHERE {
  ?country wdt:P31 wd:Q6256 ; wdt:P1081 ?hdi .
  ?hdi wikibase:quantityValue ?hdi_value .
  OPTIONAL {
    ?country wdt:P2046 ?population_growth .
    ?population_growth wikibase:quantityValue ?population_growth_value .
  }
  OPTIONAL {
    ?country wdt:P2150 ?male_suicide .
    ?male_suicide pq:P21 wd:Q6581097 .
    ?male_suicide wikibase:quantityValue ?male_value .
  }
  OPTIONAL {
    ?country wdt:P2150 ?female_suicide .
    ?female_suicide pq:P21 wd:Q6581072 .
    ?female_suicide wikibase:quantityValue ?female_value .
  }
}
ORDER BY DESC(?hdi_value)
LIMIT 10
